member.example:
Bind the AudioSource bypassReverbZones property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceBypassReverbZonesBinder _bypassReverbZones;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _bypassReverbZones;
    }


Bind the AudioSource bypassReverbZones property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceBypassReverbZonesBinder BypassReverbZones =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _bypassReverbZones;
    }
